### 2. File Stream Implementation

Implemented a `FileStream` class that inherits from `MdfStream` to handle file operations:

```cpp
class FileStream : public MdfStream {
private:
    FILE* m_file;

public:
    FileStream(const char* filename) {
        m_file = fopen(filename, "rb");
    }

    ~FileStream() {
        if (m_file) {
            fclose(m_file);
        }
    }

    virtual bool Seek(int offset, int origin) override {
        if (!m_file) return false;
        return fseek(m_file, offset, origin) == 0;
    }

    virtual int Tell() override {
        if (!m_file) return -1;
        return ftell(m_file);
    }

    virtual int Read(void *pDest, int nLength) override {
        if (!m_file) return 0;
        return fread(pDest, 1, nLength, m_file);
    }

    virtual int Length() override {
        if (!m_file) return 0;
        int pos = ftell(m_file);
        fseek(m_file, 0, SEEK_END);
        int len = ftell(m_file);
        fseek(m_file, pos, SEEK_SET);
        return len;
    }
};
```

